# Check server status
$proc = (Get-NetTCPConnection -LocalPort 10280 -ErrorAction SilentlyContinue | Where-Object { $_.State -eq 'Listen' }).OwningProcess | Where-Object { $_ -gt 0 }
if ($proc) {
    Write-Host "Server running on PID: $proc"
    $p = Get-Process -Id $proc -ErrorAction SilentlyContinue
    Write-Host "Process: $($p.ProcessName), CPU: $($p.CPU)s, Started: $($p.StartTime)"
} else {
    Write-Host "Server NOT running"
}

# Check recent logs
if (Test-Path "D:\py_app\astro_hub\logs\server.log") {
    Write-Host "`n=== Recent Logs ==="
    Get-Content "D:\py_app\astro_hub\logs\server.log" -Tail 5
}

